def token_case(s):
    """
    Converts an underscore-delimited identifier to camel case.

    Args:
        s (str): The input string in underscore-delimited form.

    Returns:
        str: The input string converted to camel case.
    """
    tokens = s.split('_')
    exceptions = ['URL', 'ID']

    def camel_case_token(token):
        if token in exceptions:
            return token
        elif token == 'id':
            # Edge case: lowercase 'id' when the second token is not in exceptions list
            return token.lower()
        else:
            return token.capitalize()

    return ''.join(camel_case_token(token) for token in tokens)
